import React from "react";
import styles from "./LoadingButton.module.css";

export interface LoadingButtonProps {
  /** Visual style */
  variant?: "primary" | "secondary" | "ghost" | "danger";
  size?: "sm" | "md" | "lg";
  disabled?: boolean;
  loading?: boolean;
  /** Button label */
  children?: React.ReactNode;
  onClick?: (event: React.MouseEvent<HTMLElement>) => void;
}

/**
 * Button with loading state
 * @generated by Component Forge — edit schema and re-run forge generate
 */
export function LoadingButton({ variant = "primary", size = "md", disabled = false, loading = false, children, onClick }: LoadingButtonProps) {

  const handleKeyDown = (event: React.KeyboardEvent<HTMLElement>) => {
    if (["Enter", " "].includes(event.key) && onClick) {
      event.preventDefault();
      onClick(event as unknown as React.MouseEvent<HTMLElement>);
    }
  };
  return (
    
      <button
      className={[styles.root, variant && styles[variant], size && styles[size]].filter(Boolean).join(" ")} data-testid="loading-button"
      type="button"
      onClick={onClick}
      disabled={disabled}
      aria-busy={loading}
      onKeyDown={handleKeyDown}
    >
      {children}
    </button>
    
  );
}

LoadingButton.displayName = "LoadingButton";
